class Program
{
    static void Main()
    {
        int[] nums = { 5, 2, 8, 1, 9, 3 };
        Array.Sort(nums);
        Console.WriteLine(String.Join(", ", nums)); // 1, 2, 3, 5, 8, 9

        Array.Reverse(nums);
        Console.WriteLine(String.Join(", ", nums)); // 9, 8, 5, 3, 2, 1

        var words = new List<string> { "banana", "apple", "cherry" };
        words.Sort();
        Console.WriteLine(String.Join(", ", words)); // apple, banana, cherry
    }
}

