class Program
{
    static void Main()
    {
        var words = new List<string> { "cherry", "fig", "apple", "date" };

        words.Sort((a, b) => a.Length.CompareTo(b.Length));
        Console.WriteLine(String.Join(", ", words)); // fig, date, apple, cherry

        words.Sort((a, b) => b.CompareTo(a)); // descending alphabetical
        Console.WriteLine(String.Join(", ", words)); // fig, date, cherry, apple
    }
}

