class Program
{
    static void Main()
    {
        int[] nums = { 5, 2, 8, 1, 9 };
        var sorted = nums.OrderBy(x => x).ToArray();
        Console.WriteLine(String.Join(", ", sorted)); // 1, 2, 5, 8, 9

        var desc = nums.OrderByDescending(x => x).ToArray();
        Console.WriteLine(String.Join(", ", desc)); // 9, 8, 5, 2, 1

        string[] words = { "banana", "fig", "apple", "date" };
        var byLen = words.OrderBy(w => w.Length).ThenBy(w => w).ToArray();
        Console.WriteLine(String.Join(", ", byLen)); // fig, date, apple, banana
    }
}

