class Program
{
    static void Main()
    {
        int[] nums = { 3, 7, 1, 9, 4, 6, 2, 8, 5 };

        var top3 = nums.OrderByDescending(x => x).Take(3);
        Console.WriteLine(String.Join(", ", top3)); // 9, 8, 7

        var bottom3 = nums.OrderBy(x => x).Take(3);
        Console.WriteLine(String.Join(", ", bottom3)); // 1, 2, 3

        int[] partial = { 5, 3, 8, 1, 9 };
        Array.Sort(partial, 1, 3);
        Console.WriteLine(String.Join(", ", partial)); // 5, 1, 3, 8, 9
    }
}

